class Node:
 """Represents a node in the Binary Search Tree"""
 def __init__(self, key):
 self.key = key
 self.left = None
 self.right = None


class BinarySearchTree:
 """Binary Search Tree implementation with all basic operations"""

 def __init__(self):
 self.root = None

 def insert(self, key):
 """Insert a new key into the BST"""
 self.root = self._insert_recursive(self.root, key)

 def _insert_recursive(self, node, key):
 if node is None:
 return Node(key)

 if key < node.key:
 node.left = self._insert_recursive(node.left, key)
 elif key > node.key:
 node.right = self._insert_recursive(node.right, key)
 # If key == node.key, do nothing (no duplicates)

 return node

 def search(self, key):
 """Search for a key in the BST"""
 return self._search_recursive(self.root, key)

 def _search_recursive(self, node, key):
 if node is None or node.key == key:
 return node

 if key < node.key:
 return self._search_recursive(node.left, key)
 return self._search_recursive(node.right, key)

 def delete(self, key):
 """Delete a key from the BST"""
 self.root = self._delete_recursive(self.root, key)

 def _delete_recursive(self, node, key):
 if node is None:
 return None

 if key < node.key:
 node.left = self._delete_recursive(node.left, key)
 elif key > node.key:
 node.right = self._delete_recursive(node.right, key)
 else:
 # Node to delete found
 # Case 1: Leaf node (no children)
 if node.left is None and node.right is None:
 return None
 # Case 2: One child
 if node.left is None:
 return node.right
 if node.right is None:
 return node.left
 # Case 3: Two children
 # Find in-order successor (smallest in right subtree)
 successor = self._find_min(node.right)
 node.key = successor.key
 node.right = self._delete_recursive(node.right, successor.key)

 return node

 def _find_min(self, node):
 """Find the node with minimum value"""
 current = node
 while current.left is not None:
 current = current.left
 return current

 def inorder(self):
 """Return list of keys in sorted order"""
 result = []
 self._inorder_recursive(self.root, result)
 return result

 def _inorder_recursive(self, node, result):
 if node:
 self._inorder_recursive(node.left, result)
 result.append(node.key)
 self._inorder_recursive(node.right, result)

 def height(self):
 """Calculate the height of the BST"""
 return self._height_recursive(self.root)

 def _height_recursive(self, node):
 if node is None:
 return -1
 left_height = self._height_recursive(node.left)
 right_height = self._height_recursive(node.right)
 return 1 + max(left_height, right_height)


# Demonstration
if __name__ == "__main__":
 bst = BinarySearchTree()

 # Insert values
 values = [8, 3, 10, 1, 6, 14, 4, 7, 13]
 print("Inserting values:", values)
 for val in values:
 bst.insert(val)

 print("In-order traversal (sorted):", bst.inorder())
 print("Tree height:", bst.height())

 # Search
 search_key = 6
 result = bst.search(search_key)
 print(f"Search for {search_key}:", "Found" if result else "Not Found")

 # Delete leaf node (case 1)
 bst.delete(4)
 print("After deleting 4 (leaf):", bst.inorder())

 # Delete node with one child (case 2)
 bst.delete(1)
 print("After deleting 1 (one child):", bst.inorder())

 # Delete node with two children (case 3)
 bst.delete(3)
 print("After deleting 3 (two children):", bst.inorder())

#include <stdio.h>
#include <stdlib.h>

// BST Node structure
typedef struct Node {
 int key;
 struct Node* left;
 struct Node* right;
} Node;

// Create a new node
Node* createNode(int key) {
 Node* newNode = (Node*)malloc(sizeof(Node));
 if (newNode == NULL) {
 printf("Memory allocation failed!\n");
 return NULL;
 }
 newNode->key = key;
 newNode->left = newNode->right = NULL;
 return newNode;
}

// Insert a key into BST
Node* insert(Node* root, int key) {
 if (root == NULL) {
 return createNode(key);
 }

 if (key < root->key) {
 root->left = insert(root->left, key);
 } else if (key > root->key) {
 root->right = insert(root->right, key);
 }
 // If key == root->key, do nothing (no duplicates)

 return root;
}

// Search for a key in BST
Node* search(Node* root, int key) {
 if (root == NULL || root->key == key) {
 return root;
 }

 if (key < root->key) {
 return search(root->left, key);
 }
 return search(root->right, key);
}

// Find node with minimum key value
Node* findMin(Node* node) {
 Node* current = node;
 while (current != NULL && current->left != NULL) {
 current = current->left;
 }
 return current;
}

// Delete a key from BST
Node* deleteNode(Node* root, int key) {
 if (root == NULL) {
 return NULL;
 }

 if (key < root->key) {
 root->left = deleteNode(root->left, key);
 } else if (key > root->key) {
 root->right = deleteNode(root->right, key);
 } else {
 // Found node to delete
 // Case 1: Leaf node (no children)
 if (root->left == NULL && root->right == NULL) {
 free(root);
 return NULL;
 }
 // Case 2: One child
 if (root->left == NULL) {
 Node* temp = root->right;
 free(root);
 return temp;
 }
 if (root->right == NULL) {
 Node* temp = root->left;
 free(root);
 return temp;
 }
 // Case 3: Two children
 Node* temp = findMin(root->right); // In-order successor
 root->key = temp->key;
 root->right = deleteNode(root->right, temp->key);
 }

 return root;
}

// In-order traversal (sorted order)
void inorder(Node* root) {
 if (root != NULL) {
 inorder(root->left);
 printf("%d ", root->key);
 inorder(root->right);
 }
}

// Pre-order traversal
void preorder(Node* root) {
 if (root != NULL) {
 printf("%d ", root->key);
 preorder(root->left);
 preorder(root->right);
 }
}

// Post-order traversal
void postorder(Node* root) {
 if (root != NULL) {
 postorder(root->left);
 postorder(root->right);
 printf("%d ", root->key);
 }
}

// Calculate height of BST
int height(Node* root) {
 if (root == NULL) {
 return -1;
 }
 int leftHeight = height(root->left);
 int rightHeight = height(root->right);
 return 1 + (leftHeight > rightHeight ? leftHeight : rightHeight);
}

// Free all nodes
void freeTree(Node* root) {
 if (root != NULL) {
 freeTree(root->left);
 freeTree(root->right);
 free(root);
 }
}

// Main function to demonstrate BST operations
int main() {
 Node* root = NULL;

 // Insert values: 8, 3, 10, 1, 6, 14, 4, 7, 13
 int values[] = {8, 3, 10, 1, 6, 14, 4, 7, 13};
 int n = sizeof(values) / sizeof(values[0]);

 printf("Inserting values: ");
 for (int i = 0; i < n; i++) {
 printf("%d ", values[i]);
 root = insert(root, values[i]);
 }
 printf("\n");

 printf("In-order traversal (sorted): ");
 inorder(root);
 printf("\n");

 printf("Tree height: %d\n", height(root));

 // Search
 int searchKey = 6;
 Node* result = search(root, searchKey);
 printf("Search for %d: %s\n", searchKey, result ? "Found" : "Not Found");

 // Delete leaf node (4)
 root = deleteNode(root, 4);
 printf("After deleting 4: ");
 inorder(root);
 printf("\n");

 // Delete node with one child (1)
 root = deleteNode(root, 1);
 printf("After deleting 1: ");
 inorder(root);
 printf("\n");

 // Delete node with two children (3)
 root = deleteNode(root, 3);
 printf("After deleting 3: ");
 inorder(root);
 printf("\n");

 // Clean up
 freeTree(root);

 return 0;
}
